const solve = (nums, queries) => {
    // 1. Preprocessing: Identify and store indices and values of even numbers in nums.
    const E_indices = [];
    const E_values = [];

    for (let i = 0; i < nums.length; i++) {
        if (nums[i] % 2 === 0) {
            E_indices.push(i);
            E_values.push(nums[i]);
        }
    }

    // Helper binary search functions (standard implementations)

    // Returns the index of the first element >= target. Returns arr.length if no such element exists.
    const lowerBound = (arr, target) => {
        let low = 0;
        let high = arr.length;
        while (low < high) {
            const mid = Math.floor((low + high) / 2);
            if (arr[mid] < target) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    };

    // Returns the index of the first element > target. Returns arr.length if no such element exists.
    const upperBound = (arr, target) => {
        let low = 0;
        let high = arr.length;
        while (low < high) {
            const mid = Math.floor((low + high) / 2);
            if (arr[mid] <= target) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    };

    const results = [];

    // 3. Query Processing
    for (const [l, r, k] of queries) {

        // Binary Search for j, where the answer X = 2j.
        // j is the rank of the even number in the full sequence {2, 4, 6, ...}.
        // Max possible j: if k=10^9 and no removals, j=10^9. If all N=10^5 are removed, j ~ 10^9 + 10^5.

        let low_j = 1;
        // Set a safe upper bound for j. Since k <= 10^9 and N <= 10^5, 10^9 + 10^5 + 1 is safe.
        let high_j = 2 * 10**9 + 2; 
        let best_j = high_j;

        while (low_j <= high_j) {
            const j = Math.floor((low_j + high_j) / 2);
            const X = 2 * j;

            // Check function: Does the count of remaining even numbers <= X satisfy >= k?

            // i. Determine the index range [p_start, p_end] in E_values corresponding to indices i in [l, r].

            // p_start: Index in E_indices where the original index >= l (first occurrence in range [l, r])
            let p_start = lowerBound(E_indices, l);

            // p_end_exclusive: Index in E_indices where the original index > r (one past the last occurrence in range [l, r])
            let p_end_exclusive = upperBound(E_indices, r);

            // If p_start >= p_end_exclusive, there are no even numbers in nums[l..r], so CountRemoved is 0.
            if (p_start >= p_end_exclusive) {
                const countRemoved = 0;
                if (j - countRemoved >= k) {
                    best_j = j;
                    high_j = j - 1;
                } else {
                    low_j = j + 1;
                }
                continue;
            }

            // ii. Count how many elements in E_values[p_start...p_end_exclusive - 1] are <= X.

            // We are counting elements <= X within E_values[p_start...p_end_exclusive - 1].

            // Find the index of the first element > X in the *entire* E_values array.
            let p_count_exclusive_total = upperBound(E_values, X);

            // We are interested in the intersection of [p_start, p_end_exclusive - 1] and [0, p_count_exclusive_total - 1].

            // The index corresponding to the last counted element (inclusive) is min(p_end_exclusive - 1, p_count_exclusive_total - 1).
            // The count is (min index + 1) - p_start.

            // p_end_exclusive - 1 is the actual last index in range [l, r] (inclusive).
            // p_count_exclusive_total - 1 is the actual last index <= X (inclusive).

            let p_end_effective = Math.min(p_end_exclusive, p_count_exclusive_total);

            let countRemoved = Math.max(0, p_end_effective - p_start);

            // Check condition
            if (j - countRemoved >= k) {
                best_j = j;
                high_j = j - 1;
            } else {
                low_j = j + 1;
            }
        }

        const result_X = 2 * best_j;
        results.push(result_X);
    }

    return results;
};

