import scala.collection.mutable

object Solution {
    // Helper function: Lower Bound (first index i such that arr[i] >= target)
    def lowerBound[T: Ordering](arr: Array[T], target: T): Int = {
        var low = 0
        var high = arr.length
        while (low < high) {
            val mid = low + (high - low) / 2
            if (arr(mid) < target) {
                low = mid + 1
            } else {
                high = mid
            }
        }
        low
    }

    // Helper function: Upper Bound (first index i such that arr[i] > target)
    def upperBound[T: Ordering](arr: Array[T], target: T): Int = {
        var low = 0
        var high = arr.length
        while (low < high) {
            val mid = low + (high - low) / 2
            if (arr(mid) <= target) {
                low = mid + 1
            } else {
                high = mid
            }
        }
        low
    }

    def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {

        // 1. Preprocessing
        val eIndices = mutable.ArrayBuffer[Int]()
        val eValues = mutable.ArrayBuffer[Long]()

        for (i <- 0 until nums.length) {
            if (nums(i) % 2 == 0L) {
                eIndices += i
                eValues += nums(i)
            }
        }

        val eIndicesArr = eIndices.toArray
        val eValuesArr = eValues.toArray

        val results = mutable.ArrayBuffer[Long]()

        // 3. Query Processing
        for (query <- queries) {
            val l = query(0).toInt
            val r = query(1).toInt
            val k = query(2)

            // Binary Search for j (the rank of the potential answer X = 2j)
            // Search range for j: [1, 2 * 10^9 + 2]
            var lowJ: Long = 1
            var highJ: Long = 2_000_000_000L + 2
            var bestJ: Long = highJ

            while (lowJ <= highJ) {
                val j = lowJ + (highJ - lowJ) / 2
                val X = 2 * j // Potential answer value

                // i. Determine index range [p_start, p_end_exclusive) in eIndices/eValues corresponding to nums[l..r].

                // p_start: Index in eIndices where original index >= l
                val pStart = lowerBound(eIndicesArr, l)

                // pEndExclusive: Index in eIndices where original index > r
                val pEndExclusive = upperBound(eIndicesArr, r)

                var countRemoved: Long = 0

                if (pStart < pEndExclusive) {
                    // ii. Count how many elements in eValuesArr[pStart...pEndExclusive - 1] are <= X.

                    // pCountExclusiveTotal: Index in eValuesArr where value > X
                    val pCountExclusiveTotal = upperBound(eValuesArr, X)

                    // Effective end index (exclusive) is the minimum of:
                    // 1. The boundary of the query range (pEndExclusive)
                    // 2. The boundary defined by X (pCountExclusiveTotal)
                    val pEndEffective = Math.min(pEndExclusive, pCountExclusiveTotal).toLong

                    // Count = effective_end - start
                    // Since pStart is Int, we cast it to Long for calculation
                    countRemoved = Math.max(0, pEndEffective - pStart.toLong)
                }

                // Check condition: (Total evens <= X) - (Count removed <= X) >= k
                // Total evens <= X is j.
                if (j - countRemoved >= k) {
                    bestJ = j
                    highJ = j - 1
                } else {
                    lowJ = j + 1
                }
            }

            val resultX = 2 * bestJ
            results += resultX
        }

        results.toArray
    }
}
